5	/// Locate the daemon binary in the target/debug/ directory.
6	fn daemon_bin() -> std::path::PathBuf {
7	    let mut p = std::env::current_dir().unwrap();
8	    for _ in 0..3 {
9	        let bin = p.join("target/debug/hd-linux-voice");
10	        if bin.exists() {
11	            return bin;
12	        }
13	        let parent = p.join("../target/debug/hd-linux-voice");
14	        if parent.exists() {
15	            return parent;
16	        }
17	        if let Some(up) = p.parent() {
18	            p = up.to_path_buf();
19	        } else {
20	            break;
21	        }
22	    }
23	    std::path::PathBuf::from("target/debug/hd-linux-voice")
24	}
