27	fn daemon_binary_does_not_link_gui_libraries() {
28	    let bin = daemon_bin();
29	    if !bin.exists() {
30	        eprintln!("Daemon binary not found at {:?}, skipping link check", bin);
31	        return;
32	    }
33	
34	    let output = Command::new("ldd").arg(&bin).output();
35	
36	    match output {
37	        Ok(out) => {
38	            let libs = String::from_utf8_lossy(&out.stdout);
39	            let forbidden = [
40	                "libwayland-client",
41	                "libX11",
42	                "libxcb",
43	                "libgtk",
44	                "libgdk",
45	            ];
46	            for lib in &forbidden {
47	                assert!(
48	                    !libs.contains(lib),
49	                    "Daemon must not link against {} (UI-01: headless only). ldd output:\n{libs}",
50	                    lib
51	                );
52	            }
53	        }
54	        Err(_) => {
55	            eprintln!("ldd not available, skipping shared library check");
56	        }
57	    }
58	}
