152	pub fn get_profiles_dir() -> Result<PathBuf> {
153	    let xdg = xdg::BaseDirectories::with_prefix("hd-linux-voice");
154	    let config_home = xdg.get_config_home()
155	        .context("Failed to determine config directory")?;
156	    let dir = config_home.join("profiles");
157	    std::fs::create_dir_all(&dir)?;
158	    Ok(dir)
