12	impl ProfileManager {
13	    /// Load the manager state from $XDG_CONFIG_HOME/hd-linux-voice/manager.yaml.
14	    pub fn load() -> Result<Self> {
15	        let path = Self::get_path()?;
16	        if !path.exists() {
17	            return Ok(Self { active_profile: None });
18	        }
19	        let file = std::fs::File::open(&path)
20	            .with_context(|| format!("Failed to open manager.yaml at {}", path.display()))?;
21	        let manager: Self = serde_yaml_ng::from_reader(file)
22	            .with_context(|| format!("Failed to parse manager.yaml at {}", path.display()))?;
23	        Ok(manager)
24	    }
25	
26	    /// Save the manager state.
27	    pub fn save(&self) -> Result<()> {
28	        let path = Self::get_path()?;
29	        // Ensure parent directory exists
30	        if let Some(parent) = path.parent() {
31	            std::fs::create_dir_all(parent)?;
32	        }
33	        let file = std::fs::File::create(&path)
34	            .with_context(|| format!("Failed to create manager.yaml at {}", path.display()))?;
35	        serde_yaml_ng::to_writer(file, self)
36	            .with_context(|| format!("Failed to serialize manager.yaml to {}", path.display()))?;
37	        Ok(())
38	    }
39	
40	    /// Get the path to manager.yaml.
41	    pub fn get_path() -> Result<PathBuf> {
42	        let xdg = xdg::BaseDirectories::with_prefix("hd-linux-voice");
43	        let config_home = xdg.get_config_home()
44	            .context("Failed to determine config directory")?;
45	        Ok(config_home.join("manager.yaml"))
46	    }
